const input = $input.first().json;
const pipeline = input.pipeline || {};
const grants = input.grants || {};
const agentHealth = input.agentHealth || [];
const recentScout = input.recentScout || [];
const openCompliance = input.openCompliance || [];
const recentRfp = input.recentRfp || [];

const today = new Date().toLocaleDateString('en-US', { timeZone: 'America/New_York', month: 'short', day: 'numeric', year: 'numeric' });

let report = 'PULSE PLATFORM REPORT\n';
report += today + ' | KAI-Netics Core Engine v2\n';
report += '================================\n\n';

// BD PIPELINE
report += 'BD PIPELINE\n';
report += '  Active MRR:      $' + (pipeline.total_active_mrr || '0') + '/mo\n';
report += '  Pipeline Value:  $' + (pipeline.total_pipeline_value || '0')+ '\n';
report += '  Stage 0 (Outreach):    ' + (pipeline.outreach_count || 0) + '\n';
report += '  Stage 1 (Discovery):   ' + (pipeline.discovery_count || 0) + '\n';
report += '  Stage 2 (POC Prop):    ' + (pipeline.poc_proposal_count || 0) + '\n';
report += '  Stage 3 (POC Exec):    ' + (pipeline.poc_execution_count || 0) + '\n';
report += '  Stage 4 (SLA Conv):    ' + (pipeline.sla_conversion_count || 0) + '\n';
report += '  Stage 5 (MRR Active):  ' + (pipeline.mrr_active_count || 0) + '\n\n';

// GRANT PIPELINE
report += 'GRANT PIPELINE\n';
report += '  LOI Drafted:     ' + (grants.loi_drafted || 0) + '\n';
report += '  LOI Sent:        ' + (grants.loi_sent || 0) + '\n';
report += '  Submitted:       ' + (grants.submitted || 0) + '\n';
report += '  Under Review:    ' + (grants.under_review || 0) + '\n';
report += '  Awarded:         ' + (grants.awarded || 0) + '\n';
report += '  Total Awarded:   $' + (grants.total_awarded || '0') + '\n';
report += '  Due in 30 days:  ' + (grants.due_in_30_days || 0) + '\n\n';

// AGENT HEALTH
report += 'AGENT HEALTH (7 days)\n';
if (agentHealth.length === 0) {
  report += '  No execution data yet\n';
} else {
  agentHealth.forEach(function(a) {
    const rate = a.success_rate_pct !== null ? a.success_rate_pct + '%' : 'N/A';
    const lastRun = a.last_run ? new Date(a.last_run).toLocaleDateString('en-US', { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit', timeZone: 'America/New_York' }) : 'Never';
    report += '  ' + a.agent + ': ' + a.total_runs + ' runs | ' + rate + ' success | Last: ' + lastRun + '\n';
  });
}
report += '\n';

// RECENT SCOUT ACTIVITY
report += 'RECENT SCOUT FINDS (last 5)\n';
if (recentScout.length === 0) {
  report += '  No Scout data yet\n';
} else {
  recentScout.forEach(function(s) {
    report += '  ' + (s.run_date || '?') + ' | ' + (s.mode || '?').toUpperCase() + ' | Score: ' + (s.fit_score || 'N/A') + ' | ' + (s.status || 'new') + '\n';
  });
}
report += '\n';

// COMPLIANCE FLAGS
report += 'OPEN COMPLIANCE ITEMS\n';
if (openCompliance.length === 0) {
  report += '  All clear\n';
} else {
  openCompliance.forEach(function(c) {
    const days = c.days_remaining !== null ? c.days_remaining + 'd' : '?';
    report += '  [' + (c.severity || '?').toUpperCase() + '] ' + c.item_name + ' -- ' + days + ' (' + (c.deadline || '?') + ')\n';
  });
}
report += '\n';

// RECENT RFP ACTIVITY
report += 'RECENT RFP ACTIVITY (last 5)\n';
if (recentRfp.length === 0) {
  report += '  No RFP data yet\n';
} else {
  recentRfp.forEach(function(r) {
    report += '  ' + (r.rfp_name || 'Unknown').substring(0, 40) + ' | ' + (r.go_no_go || '?') + ' | Score: ' + (r.fit_score || 'N/A') + ' | Decision: ' + (r.kevin_decision || 'PENDING') + '\n';
  });
}

report += '\n================================\n';
report += 'Generated: ' + new Date().toLocaleString('en-US', { timeZone: 'America/New_York' }) + ' ET\n';

// Build WhatsApp summary (shorter)
let waSummary = 'PULSE REPORT -- ' + today + '\n\n';
waSummary += 'BD: MRR $' + (pipeline.total_active_mrr || '0') + '/mo | Pipeline $' + (pipeline.total_pipeline_value || '0') + '\n';
waSummary += 'GRANTS: ' + (grants.loi_drafted || 0) + ' drafted | ' + (grants.submitted || 0) + ' submitted | $' + (grants.total_awarded || '0') + ' awarded\n';

const criticalItems = openCompliance.filter(function(c) { return c.severity === 'critical' || c.severity === 'overdue'; });
if (criticalItems.length > 0) {
  waSummary += 'COMPLIANCE FLAGS: ' + criticalItems.length + ' critical/overdue\n';
  criticalItems.forEach(function(c) {
    waSummary += '  * ' + c.item_name + ' -- ' + (c.days_remaining !== null ? c.days_remaining + 'd' : '?') + '\n';
  });
} else {
  waSummary += 'COMPLIANCE: All clear\n';
}

waSummary += 'RFP: ' + recentRfp.length + ' recent | AGENTS: ' + agentHealth.length + ' tracked';

return [{ json: {
  report: report,
  waSummary: waSummary,
  timestamp: input.timestamp
}}];

